#!/usr/bin/env bash
# workflow-5.sh — 再平衡 + 税损收割子工作流（横切，被多个主工作流复用） SOP walkthrough for 个人投资理财.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="个人投资理财"
WORKFLOW="再平衡 + 税损收割子工作流（横切，被多个主工作流复用）"

usage() {
  cat <<EOF
workflow-5.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-5.sh             # interactive
  ./workflow-5.sh --dry-run
  ./workflow-5.sh --json
  ./workflow-5.sh --explain
  ./workflow-5.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "再平衡 + 税损收割子工作流（横切，被多个主工作流复用）" 工作流。

一句话: 从「持仓权重随市场涨跌偏离了我的目标 + 应税账户有浮亏」到「权重拉回目标（纪律化低买高卖）+ 顺手实现亏损省税」—— 这是 Workflow 1/3（以及部分 2/5）都复用的**横切子工作流**，本身不产生新仓位逻辑，只维护既有组合。

入门 SOP 共 6 步, 失败模式自检 5 项。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**选再平衡方法（日历 vs 阈值）**：① **日历法**——固定周期（每年/每季）查一次并拉回；② **阈值法**——偏离超过带宽才动。两者机械执行**都优于**凭感觉择时。(evidence: [T03-S006])"
  "**（阈值法）用 5/25 规则定带宽**（Larry Swedroe，Bogleheads 收录）：当某资产类别**绝对**偏离目标 **5 个百分点**、**或相对**偏离 **25%**，取**先到者**触发再平衡。例：目标 60/40，到 65/35 或 55/45（绝对 5pp）触发；占比 < 20% 的小仓位用相对 25%（如目标 15% 国际股，偏离 ±3.75% 即 25%×15% 触发）。(evidence: [T03-S006])"
  "**优先用「新钱」再平衡**：把新供款/股息**定向**投到欠配的资产，尽量**不卖出**——零资本利得、零摩擦。(evidence: [T03-S006])"
  "**再平衡尽量在税优账户内做**：需要卖出时，优先在 401k/IRA 等税优账户里调（卖出不触发当期税），避免在 taxable 卖出产生应税利得。(evidence: [T03-S006, T03-S008])"
  "**（TLH，仅 taxable）卖浮亏 + 换相似非「实质相同」标的**：卖出浮亏标的实现亏损（抵资本利得 + 每年有限额抵普通收入），**同时**买入**相似但非 substantially identical** 的标的（如从一只标普500 ETF 换到一只全市场 ETF）维持敞口。(evidence: [T03-S007])"
  "**守 wash-sale 规则**：买入/卖出前后 **30 天**内不得买回「实质相同」标的（含配偶账户、IRA 内买回），否则亏损递延作废。(evidence: [T03-S007])"
)
declare -a FAILURE_MODES=(
  "**从不再平衡**：股票占比随牛市失控。自检：你定了日历或 5/25 触发规则吗？"
  "**在 taxable 卖出再平衡白缴税**：本可用新钱/税优账户无税完成。自检：这次再平衡能不能用新供款定向投欠配资产？"
  "**TLH 后空仓踏空**：卖了浮亏却没立刻买相似标的，错过反弹。自检：你卖出的同时买入相似非实质相同标的维持敞口了吗？"
  "**自酿 wash-sale**：30 天窗口内 DRIP/自动定投买回同标的，亏损作废。自检：你关掉了该标的的自动定投/DRIP 了吗？"
  "**把 TLH 当净省税**：忘了它是递延（降成本基准、未来 gain 更大）。自检：你记下了 TLH 后的新成本基准、想清楚未来在哪算总账了吗？"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-5-walkthrough"
fi
